using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter;

    public StringFormatterTests()
    {
        _formatter = new StringFormatter();
    }

    #region FormatPhoneNumber

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCodeInParens()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.StartsWith("(555)", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFourDigits()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.EndsWith("4567", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ContainsDashSeparator()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.Contains("-", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_MatchesExpectedFormat()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.MatchesRegex(@"^\(\d{3}\) \d{3}-\d{4}$", result);
    }

    [TestMethod]
    [DataRow("1234567890", "(123) 456-7890")]
    [DataRow("0000000000", "(000) 000-0000")]
    [DataRow("9876543210", "(987) 654-3210")]
    public void FormatPhoneNumber_VariousDigits_ReturnsExpectedFormat(string digits, string expected)
    {
        var result = _formatter.FormatPhoneNumber(digits);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void FormatPhoneNumber_Null_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _formatter.FormatPhoneNumber(null!));

        Assert.AreEqual("digits", ex.ParamName);
    }

    [TestMethod]
    [DataRow("123", DisplayName = "Too short")]
    [DataRow("12345678901", DisplayName = "Too long")]
    [DataRow("", DisplayName = "Empty")]
    public void FormatPhoneNumber_InvalidLength_ThrowsArgumentException(string digits)
    {
        var ex = Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.FormatPhoneNumber(digits));

        Assert.AreEqual("digits", ex.ParamName);
    }

    #endregion

    #region BuildGreeting

    [TestMethod]
    public void BuildGreeting_WithName_StartsWithDear()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.StartsWith("Dear", result);
    }

    [TestMethod]
    public void BuildGreeting_WithName_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.EndsWith(",", result);
    }

    [TestMethod]
    public void BuildGreeting_WithName_ContainsName()
    {
        var result = _formatter.BuildGreeting("Johnson");

        Assert.Contains("Johnson", result);
    }

    [TestMethod]
    public void BuildGreeting_DefaultTitle_ContainsMr()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.AreEqual("Dear Mr. Smith,", result);
    }

    [TestMethod]
    [DataRow("Dr.", "Jones", "Dear Dr. Jones,")]
    [DataRow("Ms.", "Garcia", "Dear Ms. Garcia,")]
    [DataRow("Prof.", "Lee", "Dear Prof. Lee,")]
    public void BuildGreeting_CustomTitle_ReturnsExpectedGreeting(string title, string name, string expected)
    {
        var result = _formatter.BuildGreeting(name, title);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void BuildGreeting_NullName_ThrowsArgumentException()
    {
        Assert.ThrowsExactly<ArgumentNullException>(
            () => _formatter.BuildGreeting(null!));
    }

    [TestMethod]
    [DataRow("", DisplayName = "Empty")]
    [DataRow("   ", DisplayName = "Whitespace")]
    public void BuildGreeting_WhitespaceName_ThrowsArgumentException(string name)
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.BuildGreeting(name));
    }

    #endregion

    #region GenerateSlug

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseSlug()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_ContainsOnlySlugChars()
    {
        var result = _formatter.GenerateSlug("C# is Great!!!");

        Assert.MatchesRegex(@"^[a-z0-9-]+$", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithLeadingTrailingSpaces_DoesNotStartWithDash()
    {
        var result = _formatter.GenerateSlug("  Hello World  ");

        Assert.StartsWith("hello", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithTrailingSpecialChars_DoesNotEndWithDash()
    {
        var result = _formatter.GenerateSlug("Hello World!!!");

        Assert.EndsWith("world", result);
    }

    [TestMethod]
    [DataRow("My Blog Post", "my-blog-post")]
    [DataRow("  Trim Me  ", "trim-me")]
    [DataRow("UPPER CASE", "upper-case")]
    [DataRow("special@#$chars", "special-chars")]
    [DataRow("multiple   spaces", "multiple-spaces")]
    public void GenerateSlug_VariousTitles_ReturnsExpectedSlug(string title, string expected)
    {
        var result = _formatter.GenerateSlug(title);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void GenerateSlug_WhitespaceOnly_ThrowsArgumentException()
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.GenerateSlug("   "));
    }

    #endregion

    #region FormatCurrency

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(9.99m);

        Assert.StartsWith("$", result);
    }

    [TestMethod]
    public void FormatCurrency_EuroSymbol_StartsWithEuro()
    {
        var result = _formatter.FormatCurrency(19.99m, "€");

        Assert.StartsWith("€", result);
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWithTwoDecimalPlaces()
    {
        var result = _formatter.FormatCurrency(50m);

        Assert.EndsWith(".00", result);
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ContainsMinusSign()
    {
        var result = _formatter.FormatCurrency(-5.50m);

        Assert.Contains("-", result);
    }

    [TestMethod]
    [DataRow(0, "$0.00")]
    [DataRow(1.5, "$1.50")]
    [DataRow(1234.56, "$1234.56")]
    [DataRow(-99.99, "$-99.99")]
    public void FormatCurrency_VariousAmounts_ReturnsExpectedFormat(double amount, string expected)
    {
        var result = _formatter.FormatCurrency((decimal)amount);

        Assert.AreEqual(expected, result);
    }

    #endregion
}

